// // This module decodes a 15-bit address to generate a 12-bit output. It sets the output to zero for addresses less than 2048, maps addresses between 2048 and 4096 directly to the lower 12 bits, and uses the upper bits for addresses greater than or equal to 4096.
module top_module(
    input [14:0] address,
    input clock,
    output reg [11:0] q
);always @(posedge clock) begin
    if(address < 15'h0800) begin
        q <= 12'h000;
    end else if(address < 15'h1000) begin
        q <= address[11:0];
    end else begin
        q <= address[14:3];
    end
end

endmodule
